    create_eas_database();

    const std::string db_path = "data/eas_database.db";

    ASSERT_TRUE(std::filesystem::exists(db_path)) 
        << "Database file " << db_path << " does not exist";

    std::ifstream file(db_path, std::ios::binary);
    ASSERT_TRUE(file.good()) 
