#include <vector>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data (const std::vector<Event>& events)  {
  using namespace sqlgen::literals;

  // 1. Create an in-memory SQLite database connection
  auto conn = sqlgen::sqlite::connect().value();

  // 2. Insert events into a temporary table using sqlgen::write()
  sqlgen::write(conn, events).value();

  // 3. Construct complex query with multiple field extractions and calculations
  auto query = sqlgen::select_from<Event>(
      "event_id"_c,
      "event_name"_c,
      sqlgen::day("start_time"_c) | sqlgen::as<"start_day">,
      sqlgen::month("start_time"_c) | sqlgen::as<"start_month">,
      sqlgen::year("start_time"_c) | sqlgen::as<"start_year">,
      sqlgen::hour("start_time"_c) | sqlgen::as<"start_hour">,
      sqlgen::minute("start_time"_c) | sqlgen::as<"start_minute">,
      sqlgen::second("start_time"_c) | sqlgen::as<"start_second">,
      sqlgen::weekday("start_time"_c) | sqlgen::as<"start_weekday">,
      sqlgen::unixepoch("start_time"_c) | sqlgen::as<"start_epoch">,
      sqlgen::days_between("start_time"_c, "end_time"_c) | sqlgen::as<"duration_days">
  )
  // 4. Apply where() condition to filter events with non-null end times
  | sqlgen::where("end_time"_c.is_not_null())
  // 5. Specify return type using sqlgen::to<std::vector<TemporalAnalysis>>
  | sqlgen::to<std::vector<TemporalAnalysis>>;

  // 6. Execute the query and return the results
  return query(conn).value();
}
}  // namespace analyze_temporal_data

