```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }

  auto conn = conn_result.value();

  // Perform upsert operation using sqlgen::write with upsert=true
  auto write_result = sqlgen::write(conn, items, true);
  if (!write_result) {
    return false; // Write operation failed
  }

  // Read back the items to verify upsert behavior
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);
  if (!read_result) {
    return false; // Read operation failed
  }

  auto read_items = read_result.value();

  // Verify that the original items match the read-back items
  if (items.size() != read_items.size()) {
    return false; // Size mismatch
  }

  for (size_t i = 0; i < items.size(); ++i) {
    if (items[i].item_id != read_items[i].item_id ||
        items[i].name != read_items[i].name ||
        items[i].quantity != read_items[i].quantity) {
      return false; // Item mismatch at index: ${i}
    }
  }

  return true; // All items matched successfully
}

}  // namespace upsert_inventory_items
```

