```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <algorithm>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
  sqlgen::PrimaryKey<std::tuple<int, int>> primary_key;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Create in-memory database connection
  auto conn = sqlgen::sqlite::connect(":memory:");

  // Create tables
  conn | create_table<User> | create_table<Friendship>;

  // Insert data
  conn | insert(users) | insert(friendships);

  // Query 1: Mutual friends using self-join and subquery
  auto mutual_friends = select_from<User, "u1">("username"_t1 | as<"user1_name">, 
                                               "username"_t2 | as<"user2_name">)
    | inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
    | inner_join<User, "u2">("user_id2"_t1 == "user_id"_t2)
    | where("user_id"_t1 < "user_id"_t2)
    | where(exists(select_from<Friendship, "f3">(1)
                  | where("user_id1"_t1 == "user_id"_t3 && "user_id2"_t1 == "user_id"_t3))
    | group_by("user_id"_t1, "user_id"_t2)
    | having(count() > 0)
    | to<std::vector<FriendConnection>>;

  // Query 2: Users with more than average friends
  auto avg_friends = select_from<User>("user_id"_t1, "username"_t1)
    | left_join<Friendship, "f">(col<"user_id">_t1 == "user_id1"_t2)
    | group_by("user_id"_t1, "username"_t1)
    | having(count() > select_from(select_from<Friendship>()
                                  | group_by("user_id1"_t2)
                                  | select(avg(count()))))
    | order_by(count().desc());

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend = select_from<User, "u1">("username"_t1 | as<"user1_name">, 
                                                   "username"_t2 | as<"user2_name">)
    | inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
    | inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
    | inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
    | where("user_id"_t1 < "user_id"_t2)
    | having(count() == 1);

  // Query 4: Friend count statistics
  auto friend_stats = select_from<User>("user_id"_t1, "username"_t1, count() | as<"friend_count">)
    | left_join<Friendship, "f">(col<"user_id">_t1 == "user_id1"_t2)
    | group_by("user_id"_t1, "username"_t1)
    | order_by(count().desc());

