                              || ("user_id2"_t1 == "user_id"_t3 && "user_id1"_t1 == "user_id"_t3)));

  // Execute all queries and combine results
  auto results = conn | mutual_friends | friend_of_friend;

  // Convert to FriendConnection format
  std::vector<FriendConnection> connections;
  for (const auto& result : results) {
    connections.push_back(FriendConnection{
        .user1_name = result.user1_name,
        .user2_name = result.user2_name
    });
