  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Create the Account table using write with an empty vector
  std::vector<Account> empty_table;
  auto write_result = sqlgen::write(conn, empty_table);
  if (!write_result) {
