  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Connect to in-memory SQLite database
  auto conn_result = sqlgen::sqlite::connect(":memory:");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Create tables using sqlgen::create_table
  auto create_dept = sqlgen::create_table<Department> | sqlgen::if_not_exists;
  auto create_emp = sqlgen::create_table<Employee> | sqlgen::if_not_exists;

  // 3. Insert data into database
  auto dept_insert_result = conn->insert(depts);
  if (!dept_insert_result) {
    throw std::runtime_error("Failed to insert departments");
  }

  auto emp_insert_result = conn->insert(emps);
  if (!emp_insert_result) {
    throw std::runtime_error("Failed to insert employees");
  }

  // 4. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2
    ) | sqlgen::inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2);

  auto inner_result = conn->read<std::vector<JoinResult>>(inner_query);
  if (!inner_result) {
    throw std::runtime_error("Failed to execute INNER JOIN");
  }
  auto inner_joins = inner_result.value();

  // 5. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(
      "department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2
    ) | sqlgen::left_join<Department, "d">("department_id"_t2 == "department_id"_t1);

  auto left_result = conn->read<std::vector<JoinResult>>(left_query);
  if (!left_result) {
    throw std::runtime_error("Failed to execute LEFT JOIN");
  }
  auto left_joins = left_result.value();

  // 6. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Employee, "e">(
      "department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2
    ) | sqlgen::right_join<Department, "d">("department_id"_t2 == "department_id"_t1);

  auto right_result = conn->read<std::vector<JoinResult>>(right_query);
  if (!right_result) {
    throw std::runtime_error("Failed to execute RIGHT JOIN");
  }
  auto right_joins = right_result.value();

  // 7. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2
    ) | sqlgen::full_join<Employee, "e">("department_id"_t1 == "department_id"_t2);

  auto full_result = conn->read<std::vector<JoinResult>>(full_query);
  if (!full_result) {
    throw std::runtime_error("Failed to execute FULL JOIN");
  }
  auto full_joins = full_result.value();

  // 8. Return comprehensive analysis
  return JoinAnalysis{
    .inner_join_results = inner_joins,
    .left_join_results = left_joins,
    .right_join_results = right_joins,
    .full_join_results = full_joins
  };
}
}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect(":memory:")` to create an in-memory SQLite database as specified.

2. **Table Creation**: Uses `sqlgen::create_table<T> | sqlgen::if_not_exists` pattern to safely create tables only if they don't exist.

3. **Data Insertion**: Uses `conn->insert()` method to insert the provided department and employee data.

4. **Join Operations**: Implements all four required join types using sqlgen's fluent API:
   - INNER JOIN: `sqlgen::inner_join<Employee, "e">`
   - LEFT JOIN: `sqlgen::left_join<Department, "d">`
   - RIGHT JOIN: `sqlgen::right_join<Department, "d">`
   - FULL JOIN: `sqlgen::full_join<Employee, "e">`

5. **Query Construction**: Uses `sqlgen::select_from` with table aliases ("d" for Department, "e" for Employee) and column selection with proper type mapping.

6. **Result Handling**: Uses `conn->read<std::vector<JoinResult>>()` to execute queries and map results to the custom `JoinResult` structure.

7. **Error Handling**: Includes basic error checking for database operations, throwing exceptions on failures.

The implementation follows sqlgen's functional programming style and properly handles the optional fields in `JoinResult` for outer join scenarios where data might be missing.

